  static const unsigned char aMap[] = {
    1, 4, 3, 2, 5
  };
  if( !sqlite3SafetyCheckOk(db) ) return sqlite3MisuseError(161043);
  ((void) sizeof ((1==1 && 2==2 && 3==3) ? 1 : 0), __extension__ ({ if (1==1 && 2==2 && 3==3) ; else __assert_fail ("OE_Rollback==1 && OE_Abort==2 && OE_Fail==3", "/home/yurii-sama/Projects/rust-sqlite/sqlite-src-3510200
  ((void) sizeof ((4==4 && 5==5) ? 1 : 0), __extension__ ({ if (4==4 && 5==5) ; else __assert_fail ("OE_Ignore==4 && OE_Replace==5", "/home/yurii-sama/Projects/rust-sqlite/sqlite-src-3510200
  ((void) sizeof ((db->vtabOnConflict>=1 && db->vtabOnConflict<=5) ? 1 : 0), __extension__ ({ if (db->vtabOnConflict>=1 && db->vtabOnConflict<=5) ; else __assert_fail ("db->vtabOnConflict>=1 && db->vtabOnConflict<=5", "/home/yurii-sama/Projects/rust-sqlite/sqlite-src-3510200
  return (int)aMap[db->vtabOnConflict-1];
}

